export interface LedgerEntryInput {
  accountKind: LedgerAccountKind;
  userId?: string;
  direction: LedgerDirection;
  amount: number; // BUG: float, không phải bigint — 0.1 + 0.2 !== 0.3
  currency: LedgerCurrency;
}

async function applyDelta(entry: LedgerEntryInput) {
  const signedAmount =
    entry.direction === LedgerDirection.CREDIT ? entry.amount : -entry.amount;
  wallet.balance = wallet.balance + signedAmount; // cộng dồn float qua thời gian sẽ lệch
}
